SqlQuery1.Open; 
if (not SqlQuery1.EOF)
{
  SqlQuery1.Edit; // Switch to edit mode
  SqlQuery1.FieldByName('Quantity').AsInteger = 10; // Make changes
  SqlQuery1.Post; // Save changes to the database
}
SqlQuery1.Close;
</pre>

