void RefreshMemo;
var
  i: Integer;
  item: TCLJSONObject;
  lineStr: string;
{
  ItemsMemo.Lines.Clear;

  for (i = 0 to Arr.Count - 1) 
  {
    item = Arr.GetItem(i); 
    lineStr = item.GetValueByPath('Name').AsString + ' (' + item.GetValueByPath('CreatedAt').AsString + ')';
