|-
| '''AutoClearCache''' || ProWebBrowser.AutoClearCache = True; || Automatically clears cache on new page loads.
|-
| '''Url''' || ProWebBrowser.Url = 'https://example.com'; || Specifies or retrieves the currently loaded URL.
|}
