  void SqLiteInsertData;
  {
    try
      Clomosy.DBSQLiteQuery.Sql.Text = '
    INSERT INTO Products (productId, productName, productPrice) VALUES (1, ''Product A'', 100.00);
    INSERT INTO Products (productId, productName, productPrice) VALUES (2, ''Product B'', 150.50);
    INSERT INTO Products (productId, productName, productPrice) VALUES (3, ''Product C'', 200.75);
    INSERT INTO Products (productId, productName, productPrice) VALUES (4, ''Product D'', 250.00);
    INSERT INTO Products (productId, productName, productPrice) VALUES (5, ''Product E'', 300.25);';
      Clomosy.DBSQLiteQuery.OpenOrExecute;

      ShowMessage('Adding data to the table was successful!');
    except
     ShowMessage('Exception Class: '+LastExceptionClassName+' Exception Message: '+LastExceptionMessage);
    }
  }

  void SqLiteConnectionCreateTable;
  var
    TableExists: Boolean;
  {
    try
      Clomosy.DBSQLiteConnect(Clomosy.AppFilesPath + 'DBProduct.db3', '');

      // Check if the table exists
      Clomosy.DBSQLiteQuery.Sql.Text = 'SELECT name FROM sqlite_master WHERE type="table" AND name="Products";';
      Clomosy.DBSQLiteQuery.OpenOrExecute;

      // Check the results
      TableExists = not Clomosy.DBSQLiteQuery.Eof;

      // Create the table if it does not exist
      if not (TableExists)
      {
        Clomosy.DBSQLiteQuery.Sql.Text = 'CREATE TABLE Products(productId INTEGER NOT NULL,
        productName TEXT NOT NULL,
        productPrice DECIMAL(18, 0) NOT NULL,
        PRIMARY KEY (productId))';
        Clomosy.DBSQLiteQuery.OpenOrExecute;

        ShowMessage('Table successfully added to the database!');
        SqLiteInsertData;
      } else
      {
        ShowMessage('The Products table already exists.');
      }


    except
     ShowMessage('Exception Class: '+LastExceptionClassName+' Exception Message: '+LastExceptionMessage);
    }
  }


