            'Alice;24;London' + #13#10 + 
            'Bob;29;Paris';

  // Save file to app directory
  clSaveToFile(filePath, CSVText);

  // Initialize share service and share the file
  ShareService = TclShareService.Create;
  ShareService.AddFile(filePath);
